noncompliant:
// Redefining without undefining first
#define MAX_SIZE 100
// ... later in code
#define MAX_SIZE 200 // Non-compliant redefinition

// Another example
#define DEBUG 1
#define DEBUG 0 // Non-compliant

compliant:
// Properly undefine before redefining
#define MAX_SIZE 100
// ... later in code
#undef MAX_SIZE
#define MAX_SIZE 200 // Compliant

// Exception: Same value redefinition is allowed
#define VERSION 1
#define VERSION 1 // Compliant - same value

// Better approach: use different names
#define INITIAL_MAX_SIZE 100
#define UPDATED_MAX_SIZE 200
